const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // Parse group records from JSON
  let groupRecords = d.group_records;
  if (typeof groupRecords === 'string') {
    try {
      groupRecords = JSON.parse(groupRecords);
    } catch(e) {
      continue;
    }
  }

  // Skip groups with only 1 record
  if (!groupRecords || groupRecords.length < 2) {
    continue;
  }

  // Sort by created_at ASC — oldest is primary
  groupRecords.sort((a, b) =>
    new Date(a.created_at) - new Date(b.created_at)
  );

  const primary = groupRecords[0];
  const duplicates = groupRecords.slice(1);

  // ── NULL-SAFE MERGE LOGIC ──
  // Never overwrite non-empty primary field
  // with empty duplicate field
  let mergedName = primary.full_name;
  let mergedEmail = primary.email;
  let mergedPhone = primary.phone;
  let mergedCompany = primary.company;
  let mergedTitle = primary.job_title;
  const mergedFields = [];
  const absorbedIds = [];

  for (const dup of duplicates) {
    absorbedIds.push(dup.record_id);

    // Only fill if primary field is null/empty
    if (!mergedEmail && dup.email) {
      mergedEmail = dup.email;
      mergedFields.push('email from ' + dup.record_id);
    }
    if (!mergedPhone && dup.phone) {
      mergedPhone = dup.phone;
      mergedFields.push('phone from ' + dup.record_id);
    }
    if (!mergedCompany && dup.company) {
      mergedCompany = dup.company;
      mergedFields.push(
        'company from ' + dup.record_id
      );
    }
    if (!mergedName && dup.full_name) {
      mergedName = dup.full_name;
      mergedFields.push(
        'full_name from ' + dup.record_id
      );
    }
    if (!mergedTitle && dup.job_title) {
      mergedTitle = dup.job_title;
      mergedFields.push(
        'job_title from ' + dup.record_id
      );
    }
  }

  // ── SAFE SQL ESCAPE FUNCTION ──
  const escSql = (val) => {
    if (val === null || val === undefined) 
      return 'NULL';
    return "'" + 
      String(val).replace(/'/g, "''") + 
      "'";
  };

  // ── GENERATE SQL UPDATE FOR PRIMARY ──
  const updateSql = `
UPDATE _learnersRaw SET
  full_name = ${escSql(mergedName)},
  email = ${escSql(mergedEmail)},
  phone = ${escSql(mergedPhone)},
  company = ${escSql(mergedCompany)},
  job_title = ${escSql(mergedTitle)},
  stage = 'S5',
  status = 'merged',
  updated_at = NOW()
WHERE record_id = ${escSql(primary.record_id)};
  `.trim();

  // ── GENERATE SQL TO ABSORB DUPLICATES ──
  const absorbSql = absorbedIds.map(id => `
UPDATE _learnersRaw SET
  stage = 'S4_ABSORBED',
  status = 'absorbed',
  merged_into = ${escSql(primary.record_id)},
  updated_at = NOW()
WHERE record_id = ${escSql(id)};
  `.trim()).join('\n');

  results.push({
    json: {
      normalized_url: d.normalized_url,
      primary_record_id: primary.record_id,
      primary_name: mergedName,
      primary_email: mergedEmail,
      primary_phone: mergedPhone,
      primary_company: mergedCompany,
      primary_title: mergedTitle,
      absorbed_ids: absorbedIds.join(','),
      merged_fields: mergedFields.join(', ') || 'none',
      group_size: groupRecords.length,
      update_sql: updateSql,
      absorb_sql: absorbSql,
      full_sql: updateSql + '\n' + absorbSql,
      merged_at: new Date().toISOString()
    }
  });
}

// Safety check
if (results.length === 0) {
  return [{
    json: {
      error: true,
      message: 'No valid S4 groups found to merge',
      skipped: true
    }
  }];
}

return results;
